# i18n.py
"""Traducción ligera de los TEXTOS VISIBLES de Imago (Español / Inglés / Francés).

Solo afecta a cadenas que se ven en pantalla (menús, botones, etiquetas,
tooltips, títulos, mensajes...). No toca comentarios ni claves internas.

Uso:
    from i18n import t
    boton.setText(t("common.close"))
    label.setText(t("about.version", v=APP_VERSION))

El idioma activo lo fija main.py al arrancar (desde Preferencias / QSettings),
así que este módulo no depende de QSettings. Si falta una traducción, cae al
español; si falta la clave entera, devuelve la propia clave (no rompe la UI).
El cambio de idioma se aplica al reiniciar la app.
"""

_LANG = "es"   # idioma activo ('es' | 'en' | 'fr')

# Idiomas soportados (para poblar el desplegable de Preferencias).
LANGUAGES = (("es", "Español"), ("en", "English"), ("fr", "Français"))


def set_language(lang):
    """Fija el idioma activo. Cualquier valor no soportado cae a 'es'."""
    global _LANG
    _LANG = lang if lang in ("es", "en", "fr") else "es"


def current_language():
    return _LANG


def t(key, **kwargs):
    """Texto traducido para 'key' en el idioma activo. Acepta variables con
    formato: t("layer.copy_name", name="Fondo")."""
    entry = _STRINGS.get(key)
    if entry is None:
        text = key                       # fallback: la clave (evita crashear)
    else:
        text = entry.get(_LANG) or entry.get("es") or key
    if kwargs:
        try:
            text = text.format(**kwargs)
        except (KeyError, IndexError, ValueError):
            pass
    return text


def registrar_strings(nuevas):
    """Inyecta traducciones en caliente (clave -> {"es":..., "en":..., "fr":...}).

    Lo usan los PLUGINS de terceros para dar de alta sus propios textos sin tocar
    este archivo. No pisa una clave que ya exista en el diccionario base (los
    textos de Imago mandan). `nuevas` es un dict con el mismo formato que _STRINGS.
    """
    if not isinstance(nuevas, dict):
        return
    for clave, valores in nuevas.items():
        if clave not in _STRINGS and isinstance(valores, dict):
            _STRINGS[clave] = valores


